    const gert::Shape *anchor_shape = context->GetInputShape(0);
    uint32_t totalN = anchor_shape->GetDim(0);
    uint32_t totalD = anchor_shape->GetDim(1);

    // UB budget: per-row buffers (anchor, positive, negative, diff, sq) + reduction workspace
    uint32_t bytesPerRow = 5 * totalD * sizeof(float) + 16 * sizeof(float);
    uint32_t maxBatch = UB_BUDGET_BYTES / bytesPerRow;
    maxBatch = AlignDown(maxBatch, 1u);
    if (maxBatch == 0) maxBatch = 1;
    uint32_t tileBatch = (totalN < maxBatch) ? totalN : maxBatch;

    uint32_t blockDim = 1;
    context->SetBlockDim(blockDim);

    tiling.set_totalN(totalN);
    tiling.set_totalD(totalD);
    tiling.set_tileBatch(tileBatch);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

